import { supabase } from '../lib/supabase';
import type { UserType } from '../types';

export const authService = {
    async register(email: string, password: string, userType: UserType, fullName: string) {
        const { data, error } = await supabase.auth.signUp({
            email,
            password,
            options: {
                data: {
                    user_type: userType,
                    full_name: fullName,
                },
            },
        });

        if (error) throw error;

        // Create public user profile trigger would ideally handle this, 
        // but for now we might rely on a manual insert if trigger isn't set up.
        // For this plan, we'll assume the client does it or a trigger exists. 
        // Let's do it manually to be safe for a "scratch" build without complex SQL triggers yet.
        if (data.user) {
            const { error: profileError } = await supabase.from('users').insert({
                id: data.user.id,
                email: email,
                user_type: userType,
                full_name: fullName
            });
            if (profileError) {
                console.error('Error creating user profile:', profileError);
                throw new Error(`Profile creation failed: ${profileError.message}`);
            }
        }

        return data;
    },

    async login(email: string, password: string) {
        const { data, error } = await supabase.auth.signInWithPassword({
            email,
            password,
        });
        if (error) throw error;
        return data;
    },

    async logout() {
        const { error } = await supabase.auth.signOut();
        if (error) throw error;
    },

    async getCurrentUser() {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return null;

        // Fetch WBSP profile data
        const { data: profile } = await supabase
            .from('users')
            .select('*')
            .eq('id', user.id)
            .single();

        if (!user || !profile) return null;

        return {
            id: user.id,
            email: user.email!, // Supabase user always has email if logged in via email
            fullName: profile.full_name,
            userType: profile.user_type,
            avatarUrl: profile.avatar_url || `https://i.pravatar.cc/150?u=${user.email}`,
            // Map other potential fields if they exist in schema
        };
    }
};
